[
  {
    "name": "review_plan",
    "parameters": {
      "plan_description": "Modify /etc/postfix/main.cf to restrict client connections to the local network by setting smtpd_client_restrictions = permit_mynetworks,reject"
    }
  },
  {
    "name": "run_cmd",
    "parameters": {
      "command": "sed -i 's/^smtpd_client_restrictions.*/smtpd_client_restrictions = permit_mynetworks,reject/g' /etc/postfix/main.cf"
    }
  }
}
